+function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
+  if (mode === 'none') return false;
+  const node = line.includes('node:internal');
+  const superjson =
+    line.includes('src/transformer.ts') ||
