+    line.includes('src/index.ts');
+  return (
+    (mode === 'node' && node) ||
+    (mode === 'superjson' && superjson) ||
+    (mode === 'node_and_superjson' && (node || superjson))
+  );
+}
+
+function redactLine(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'strip_cwd') {
+    return line.split(process.cwd()).join('');
+  }
+  if (mode === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?(?:[\\\\/][^\\\\/\\s():]+)+/g, path => {
+      const parts = path.split(/[\\\\/]/);
+      return parts[parts.length - 1] || path;
+    });
+  }
+  return line;
+}
